configFiles.template:
// Set the Host Name
hostname "${Hostname}" 

// Set the rcon password 
rcon_password "${RconPassword}"
sv_password "${PrivatePassword}" 

// Fast downloads
sv_downloadurl "${FastDownloadUrl}"
sv_allowdownload ${FastDownloadEnabled}
sv_allowupload 1

// Exec files on startup 
exec banned.cfg
exec listip.cfg

// Server Logging
log ${Log}
mp_logdetail ${LogDetail}
mp_logmessages ${LogMessages}


// Server Variables
mp_timelimit ${TimeLimit}
mp_autokick ${AutoKick}
mp_autoteambalance ${AutoTeamBalance}
mp_c4timer ${C4Timer}
mp_flashlight ${Flashlight}
mp_footsteps ${FootSteps}
mp_forcechasecam ${ForceChaseCam}
mp_freezetime ${FreezeTime}
mp_friendlyfire ${FriendlyFire}
mp_hostagepenalty ${HostagePenalty}
mp_limitteams ${LimitTeams}
mp_roundtime ${RoundTime}
mp_tkpunish ${TKPunish}
sv_restartround ${RestartRound}
sv_maxspeed ${MaxSpeed}
sv_proxies ${Proxies}
allow_spectators ${Spectators}
mp_startmoney ${StartMoney}
mp_chattime ${ChatTime}
sv_allowupload ${AllowUpload}
sv_voiceenable ${VoiceEnable}
sv_alltalk ${AllTalk}


pausable ${Pausable}
decalfrequency ${DecalFrequency}
mp_falldamage ${FallDamage}

// cheat and fun modes
sv_aim ${Aim}
sv_cheats ${Cheat}

// Set Rates
sv_maxrate ${MaxRate}
sv_minrate ${MinRate}


// Contact & Geo
sv_contact ${Contact}
sv_region ${Region}
